export THIRD_PARTY_GLU3_PREFIX="${THIRD_PARTY_GLU3_PREFIX:-/opt/third_party/install/glu3}"
export THIRD_PARTY_PASTIX_CPU_PREFIX="${THIRD_PARTY_PASTIX_CPU_PREFIX:-/opt/third_party/install/pastix-cpu}"
export THIRD_PARTY_PASTIX_CUDA_PREFIX="${THIRD_PARTY_PASTIX_CUDA_PREFIX:-/opt/third_party/install/pastix-cuda}"
export THIRD_PARTY_PANGULU_PREFIX="${THIRD_PARTY_PANGULU_PREFIX:-/opt/third_party/install/pangulu}"
