export DATASETS_ROOT="${DATASETS_ROOT:-/datasets}"
export POWER_SYSTEM_DATASET_ROOT="${POWER_SYSTEM_DATASET_ROOT:-${DATASETS_ROOT}/power_system}"
export MATPOWER_DATASET_ROOT="${MATPOWER_DATASET_ROOT:-${POWER_SYSTEM_DATASET_ROOT}/matpower}"
export MATPOWER_MAT_ROOT="${MATPOWER_MAT_ROOT:-${POWER_SYSTEM_DATASET_ROOT}/matpower_mat}"
