export PATH="${THIRD_PARTY_COMMON_PREFIX}/bin:${THIRD_PARTY_STRUMPACK_CUDA_PREFIX}/bin:${THIRD_PARTY_STRUMPACK_CPU_PREFIX}/bin:${THIRD_PARTY_GLU3_PREFIX}/bin:${THIRD_PARTY_PASTIX_CUDA_PREFIX}/bin:${THIRD_PARTY_PASTIX_CPU_PREFIX}/bin:${THIRD_PARTY_PANGULU_PREFIX}/bin:${THIRD_PARTY_MUMPS_PREFIX}/bin:${CUDSS_DIR}/bin:${CUDA_HOME}/bin:/usr/local/bin:${PATH}"
export LD_LIBRARY_PATH="${CUDSS_DIR}/lib:${THIRD_PARTY_COMMON_PREFIX}/lib:${THIRD_PARTY_COMMON_PREFIX}/lib64:${THIRD_PARTY_STRUMPACK_CUDA_PREFIX}/lib:${THIRD_PARTY_STRUMPACK_CUDA_PREFIX}/lib64:${THIRD_PARTY_STRUMPACK_CPU_PREFIX}/lib:${THIRD_PARTY_STRUMPACK_CPU_PREFIX}/lib64:${THIRD_PARTY_GLU3_PREFIX}/lib:${THIRD_PARTY_GLU3_PREFIX}/lib64:${THIRD_PARTY_PASTIX_CUDA_PREFIX}/lib:${THIRD_PARTY_PASTIX_CUDA_PREFIX}/lib64:${THIRD_PARTY_PASTIX_CPU_PREFIX}/lib:${THIRD_PARTY_PASTIX_CPU_PREFIX}/lib64:${THIRD_PARTY_PANGULU_PREFIX}/lib:${THIRD_PARTY_PANGULU_PREFIX}/lib64:${THIRD_PARTY_MUMPS_PREFIX}/lib:${THIRD_PARTY_MUMPS_PREFIX}/lib64:${MKLROOT}/lib:${MKLROOT}/lib/intel64:${LD_LIBRARY_PATH:-}"
export CMAKE_PREFIX_PATH="${THIRD_PARTY_COMMON_PREFIX}:${THIRD_PARTY_STRUMPACK_CUDA_PREFIX}:${THIRD_PARTY_STRUMPACK_CPU_PREFIX}:${THIRD_PARTY_GLU3_PREFIX}:${THIRD_PARTY_PASTIX_CUDA_PREFIX}:${THIRD_PARTY_PASTIX_CPU_PREFIX}:${THIRD_PARTY_PANGULU_PREFIX}:${THIRD_PARTY_MUMPS_PREFIX}:/opt/intel/oneapi:${CUDSS_DIR}:${CMAKE_PREFIX_PATH:-}"
export PKG_CONFIG_PATH="${THIRD_PARTY_COMMON_PREFIX}/lib/pkgconfig:${THIRD_PARTY_COMMON_PREFIX}/lib64/pkgconfig:${THIRD_PARTY_MUMPS_PREFIX}/lib/pkgconfig:${PKG_CONFIG_PATH:-}"
export CPATH="${CUDSS_DIR}/include:${CUDA_HOME}/include:${THIRD_PARTY_GLU3_PREFIX}/include:${THIRD_PARTY_PANGULU_PREFIX}/include:${MKLROOT}/include:${CPATH:-}"
